from typing import List

def get_maximum_free_days(N: int, D: int, S: List[str]) -> int:
    # Count the number of consecutive days where all people are free
    count = 0
    highest_count = 0
    for i in range(len(S[0])):
        for j in range(N):
            if S[j][i] == 'o':
                count += 1
            else:
                count = 0
            highest_count = max(highest_count, count)
    highest_count = max(highest_count, count)
    # If the highest count is D, then the answer is D, otherwise 0
    return D if highest_count == D else 0

